import { CheckoutFlow } from "@/components/checkout/CheckoutFlow";
import { getServerLanguage } from "@/lib/server-language";
import { getCheckoutData, requireAuthenticatedUser } from "@/lib/storefront-data";
import { getMessages } from "@/lib/storefront";

export const dynamic = "force-dynamic";

export default async function CheckoutPage() {
  const language = await getServerLanguage();
  const messages = getMessages(language);
  const { user } = await requireAuthenticatedUser();
  const { profile, addresses } = await getCheckoutData(user.id);

  return (
    <div className="space-y-10">
      <section className="soft-panel px-6 py-10 sm:px-8 lg:px-12 lg:py-14">
        <div className="text-start">
          <p className="eyebrow">{messages.checkout.title}</p>
          <h1 className="mt-4 text-4xl font-bold tracking-tight text-[#1D1D1F] sm:text-5xl">
            {messages.checkout.title}
          </h1>
          <p className="mt-5 max-w-3xl text-lg leading-8 text-slate-500">
            {language === "ar"
              ? "ثلاث خطوات واضحة: عنوان التوصيل، الدفع، ثم مراجعة الطلب قبل التأكيد النهائي."
              : "Three clear steps: delivery address, payment, then a final review before confirmation."}
          </p>
        </div>
      </section>

      <CheckoutFlow profile={profile} addresses={addresses} />
    </div>
  );
}
